const OPENAI_API_KEY = "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";

// ✨ GENERATE BLOG
export async function generateBlog(title) {
  try {
    const res = await fetch("https://api.openai.com/v1/chat/completions", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${OPENAI_API_KEY}`,
      },
      body: JSON.stringify({
        model: "gpt-4o-mini",
        messages: [
          {
            role: "system",
            content:
              "Write a detailed blog article (400-700 words) in simple English with headings and paragraphs.",
          },
          {
            role: "user",
            content: title,
          },
        ],
      }),
    });

    const data = await res.json();

    if (!res.ok) {
      console.error(data);
      throw new Error("API failed");
    }

    return data.choices?.[0]?.message?.content || "";
  } catch (err) {
    console.error(err);
    return "Failed to generate blog. Check API key.";
  }
}

// 🏷️ GENERATE TAGS USING AI
export async function generateTags(title, content) {
  try {
    const res = await fetch("https://api.openai.com/v1/chat/completions", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${OPENAI_API_KEY}`,
      },
      body: JSON.stringify({
        model: "gpt-4o-mini",
        messages: [
          {
            role: "system",
            content:
              "Generate 5 short tags (single words) for a blog. Return only comma-separated words.",
          },
          {
            role: "user",
            content: `${title}\n${content}`,
          },
        ],
      }),
    });

    const data = await res.json();

    if (!res.ok) {
      console.error(data);
      throw new Error("API failed");
    }

    const text = data.choices?.[0]?.message?.content || "";

    return text
      .split(",")
      .map((t) => t.trim().toLowerCase())
      .filter(Boolean);
  } catch (err) {
    console.error(err);
    return ["blog"];
  }
}
